bool npc_is_at_assigned_camp( const npc &n )
{
    if( !n.assigned_camp ) {
        return false;
    }
    const std::optional<basecamp *> camp = overmap_buffer.find_camp( n.assigned_camp->xy() );
    if( camp && *camp ) {
        return ( *camp )->point_within_camp( n.pos_abs_omt() );
    }
    return n.pos_abs_omt() == *n.assigned_camp;
}

